select
(case
    when a.dept_id = '620000' then a.dept_id
    when a.dept_id like '626%' then a.dept_id
    else rpad(substr(a.dept_id, 1, 4), 6, 0)
end) as `sjdm`,
sum(je) je
from gh_hkxx a
left join gh_hkxx_qrsz b on b.hkxx_id = a.hkxx_id

